/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Movimento Bancário"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &MovCreDeb.IsEmpty() &FilterMovCreDebValueDescription = '' Do Case Case &MovCreDeb.ToString().Trim() = !"C" &FilterMovCreDebValueDescription = "Crédito"
Case &MovCreDeb.ToString().Trim() = !"D" &FilterMovCreDebValueDescription = "Débito"
EndCase
print printBlockFilterMovCreDeb EndIf If not &MovTip.IsEmpty() &FilterMovTipValueDescription = &MovTip.EnumerationDescription()
print printBlockFilterMovTip EndIf If not &MovDtaCon.IsEmpty() print printBlockFilterMovDtaCon EndIf If not &MovDtaCon_To.IsEmpty() &MovDtaCon_To_Description = format('%1 (%2)', "D.", " - ") print printBlockFilterMovDtaCon_To EndIf If not &MovSts.IsEmpty() &FilterMovStsValueDescription = &MovSts.EnumerationDescription()
print printBlockFilterMovSts EndIf If not &MovCtaBanCod.IsEmpty() print printBlockFilterMovCtaBanCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'MOVDOC' &MovDoc1.FromString(&GridStateDynamicFilter.Value) If not &MovDoc1.IsEmpty() &MovDoc = &MovDoc1 print printBlockFilterMovDoc EndIf Case &DynamicFiltersSelector1 = !'MOVCOD' &MovCod1.FromString(&GridStateDynamicFilter.Value) If not &MovCod1.IsEmpty() &MovCod = &MovCod1 print printBlockFilterMovCod EndIf Case &DynamicFiltersSelector1 = !'MOVVLR' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &MovVlr1.FromString(&GridStateDynamicFilter.Value) If not &MovVlr1.IsEmpty() Do Case Case &DynamicFiltersOperator1 = 0 &FilterMovVlrDescription = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator1 = 1 &FilterMovVlrDescription = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator1 = 2 &FilterMovVlrDescription = format('%1 (%2)', "Valor", ">") EndCase &MovVlr = &MovVlr1 print printBlockFilterMovVlr EndIf Case &DynamicFiltersSelector1 = !'MOVCPLTOT' &MovCplTot1.FromString(&GridStateDynamicFilter.Value) If not &MovCplTot1.IsEmpty() &MovCplTot = &MovCplTot1 print printBlockFilterMovCplTot EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'MOVDOC' &MovDoc2.FromString(&GridStateDynamicFilter.Value) If not &MovDoc2.IsEmpty() &MovDoc = &MovDoc2 print printBlockFilterMovDoc EndIf Case &DynamicFiltersSelector2 = !'MOVCOD' &MovCod2.FromString(&GridStateDynamicFilter.Value) If not &MovCod2.IsEmpty() &MovCod = &MovCod2 print printBlockFilterMovCod EndIf Case &DynamicFiltersSelector2 = !'MOVVLR' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &MovVlr2.FromString(&GridStateDynamicFilter.Value) If not &MovVlr2.IsEmpty() Do Case Case &DynamicFiltersOperator2 = 0 &FilterMovVlrDescription = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator2 = 1 &FilterMovVlrDescription = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator2 = 2 &FilterMovVlrDescription = format('%1 (%2)', "Valor", ">") EndCase &MovVlr = &MovVlr2 print printBlockFilterMovVlr EndIf Case &DynamicFiltersSelector2 = !'MOVCPLTOT' &MovCplTot2.FromString(&GridStateDynamicFilter.Value) If not &MovCplTot2.IsEmpty() &MovCplTot = &MovCplTot2 print printBlockFilterMovCplTot EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'MOVDOC' &MovDoc3.FromString(&GridStateDynamicFilter.Value) If not &MovDoc3.IsEmpty() &MovDoc = &MovDoc3 print printBlockFilterMovDoc EndIf Case &DynamicFiltersSelector3 = !'MOVCOD' &MovCod3.FromString(&GridStateDynamicFilter.Value) If not &MovCod3.IsEmpty() &MovCod = &MovCod3 print printBlockFilterMovCod EndIf Case &DynamicFiltersSelector3 = !'MOVVLR' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &MovVlr3.FromString(&GridStateDynamicFilter.Value) If not &MovVlr3.IsEmpty() Do Case Case &DynamicFiltersOperator3 = 0 &FilterMovVlrDescription = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator3 = 1 &FilterMovVlrDescription = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator3 = 2 &FilterMovVlrDescription = format('%1 (%2)', "Valor", ">") EndCase &MovVlr = &MovVlr3 print printBlockFilterMovVlr EndIf Case &DynamicFiltersSelector3 = !'MOVCPLTOT' &MovCplTot3.FromString(&GridStateDynamicFilter.Value) If not &MovCplTot3.IsEmpty() &MovCplTot = &MovCplTot3 print printBlockFilterMovCplTot EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod MovCtaBanCod MovDtaCon MovCod when &OrderedBy = 1 order EmpCod MovCtaBanCod (MovDtaCon) (MovCod) when &OrderedBy = 2 order MovCod when &OrderedBy = 3 AND &OrderedDsc = False order (MovCod) when &OrderedBy = 3 AND &OrderedDsc = True order MovDtaCon when &OrderedBy = 4 AND &OrderedDsc = False order (MovDtaCon) when &OrderedBy = 4 AND &OrderedDsc = True order MovDoc when &OrderedBy = 5 AND &OrderedDsc = False order (MovDoc) when &OrderedBy = 5 AND &OrderedDsc = True order MovVlr when &OrderedBy = 6 AND &OrderedDsc = False order (MovVlr) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWMovimento(&MovCreDeb, &MovTip, &MovDtaCon, &MovDtaCon_To, &MovSts, &MovCtaBanCod , &DynamicFiltersSelector1, &DynamicFiltersOperator1, &MovDoc1, &MovCod1, &MovVlr1, &MovCplTot1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &DynamicFiltersOperator2, &MovDoc2, &MovCod2, &MovVlr2 , &MovCplTot2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &MovDoc3, &MovCod3 , &MovVlr3, &MovCplTot3) &gridMovTip = MovTip &gridMovTipDescription = &gridMovTip.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWMovimentoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWMovimentoGridState")) Else &GridState.FromXml(&Session.Get(!"WWMovimentoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"MOVCREDEB" &MovCreDeb.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MOVTIP" &MovTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MOVDTACON" &MovDtaCon.FromString(&GridStateFilterValue.Value) &MovDtaCon_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"MOVSTS" &MovSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MOVCTABANCOD" &MovCtaBanCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PARM_&AUXMOVCTABANCOD" &AuxMovCtaBanCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
